def is_blunt_weapon(weapon):
    blunt_weapons = {"wooden pestle", "iron baton", "wooden club"}
    sharp_weapons = {"fruit knife", "dagger", "sword"}
    return weapon.lower() in blunt_weapons

def analyze_sound_evidence(weapon):
    if is_blunt_weapon(weapon):
        return "The weapon matches the 'dull thud' sound described at the crime scene."
    else:
        return "The weapon does not match the 'dull thud' sound; it may be too quiet or sharp to produce the described noise."

# Example usage:
print(analyze_sound_evidence("wooden pestle"))  # Output: Matches the 'dull thud'
print(analyze_sound_evidence("fruit knife"))    # Output: Does not match
